const rows = Array.isArray($input.item.json) ? $input.item.json : [];
const yesterday = new Date(Date.now() - 86400000).toISOString().slice(0,10);
const byService = {};
rows.forEach(function (r) { (byService[r.service_name] = byService[r.service_name] || []).push({ d: r.tracking_date, c: parseInt(r.spend_cents) || 0 }); });
const anomalies = [];
Object.keys(byService).forEach(function (svc) {
  const series = byService[svc];
  const ydayRow = series.find(function (r) { return r.d === yesterday; });
  if (!ydayRow || ydayRow.c === 0) return;
  const baseline = series.filter(function (r) { return r.d !== yesterday; });
  if (baseline.length < 7) return;  // need >= 7 days of history to compute baseline
  const avg = baseline.reduce(function (a, r) { return a + r.c; }, 0) / baseline.length;
  if (avg < 10) return;  // skip noise on near-zero baselines (< 10 cents/day)
  const ratio = ydayRow.c / avg;
  if (ratio >= 2) {
    anomalies.push({ service: svc, yesterday_cents: ydayRow.c, baseline_avg_cents: Math.round(avg), ratio: Math.round(ratio * 10) / 10 });
  }
});
return { json: { anomalies, services_evaluated: Object.keys(byService).length } };
